async function seed() {
  const databaseUrl = process.env.PROD_DATABASE_URL || process.env.DATABASE_URL;
  if (!databaseUrl) {
    console.error("DATABASE_URL not set");
    process.exit(1);
  }

  const pool = new Pool({ connectionString: databaseUrl });

  console.log(`Batch 2 — Total questions to insert: ${allBatch2.length}`);

  const distribution: Record<string, number> = {};
  const diffDist: Record<number, number> = {};
  const cogDist: Record<string, number> = {};

  for (const q of allBatch2) {
    distribution[q.blueprintCategory] = (distribution[q.blueprintCategory] || 0) + 1;
    diffDist[q.difficulty] = (diffDist[q.difficulty] || 0) + 1;
    cogDist[q.cognitiveLevel] = (cogDist[q.cognitiveLevel] || 0) + 1;
  }

  console.log("Batch 2 distribution by discipline:", distribution);
  console.log("Batch 2 distribution by difficulty:", diffDist);
  console.log("Batch 2 distribution by cognitive level:", cogDist);

  let inserted = 0;
  let errors = 0;

  for (let i = 0; i < allBatch2.length; i++) {
    const q = allBatch2[i];
    try {
      await pool.query(
        `INSERT INTO allied_questions (
          id, career_type, stem, options, correct_answer, rationale_long,
          learning_objective, blueprint_category, subtopic, difficulty,
          cognitive_level, question_type, status, created_at
        ) VALUES (
          gen_random_uuid(), 'mlt', $1, $2, $3, $4,
          $5, $6, $7, $8,
          $9, 'mcq', 'active', NOW()
        )`,
        [
          q.stem,
          JSON.stringify(q.options),
          q.correctAnswer,
          q.rationaleLong,
          q.learningObjective,
          q.blueprintCategory,
          q.subtopic,
          q.difficulty,
          q.cognitiveLevel,
        ]
      );
      inserted++;
    } catch (e: any) {
      console.error(`Error inserting question ${i + 1}: ${e.message}`);
      errors++;
    }
  }

  console.log(`\nBatch 2 Inserted: ${inserted}, Errors: ${errors}`);

  const totalResult = await pool.query("SELECT COUNT(*) as cnt FROM allied_questions WHERE career_type ILIKE '%mlt%' AND status = 'active'");
  console.log(`Total active MLT questions in database: ${totalResult.rows[0].cnt}`);

  await pool.end();
}

seed().catch(console.error);
